#!/bin/bash
c0="‚Äã";c1="‚ÅÝ";case $1 in -01) s=$(cat 01.txt);o="";for((i=0;i<${#s};i++));do ch="${s:$i:1}";[ "$ch" = "$c0" ]&&o+="0";[ "$ch" = "$c1" ]&&o+="1";done;echo "\"$o\"";;-0f) s=$(cat 0f.txt);o="";val=0;bits=0;for((i=0;i<${#s};i++));do ch="${s:$i:1}";[ "$ch" = "$c1" ]&&((val|=1<<(3-bits)));((bits++));if((bits==4));then printf -v hex "%X" "$val";o+="$hex";val=0;bits=0;fi;done;echo "\"$o\"";;-text) s=$(cat text.txt);o="";val=0;bits=0;for((i=0;i<${#s};i++));do ch="${s:$i:1}";[ "$ch" = "$c1" ]&&((val|=1<<(7-bits)));((bits++));if((bits==8));then printf -v char "\\x$(printf "%02x" "$val")";o+="$char";val=0;bits=0;fi;done;echo -e "\"$o\"";;*) echo "–ò—Å–ø–æ–ª—å–∑—É–π -01, -0f –∏–ª–∏ -text";exit 1;;esac
